import '../lib/redirect_follower.dart';
import '../lib/redirect_request.dart';
import '../lib/redirect_response.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

bool hasHeader(Map<String, String> headers, String name) {
  final normalized = name.toLowerCase();
  return headers.keys.any((key) => key.toLowerCase() == normalized);
}

class CredentialReturningPolicy extends RedirectPolicy {
  @override
  RedirectRequest derive(
    RedirectRequest current, {
    required int statusCode,
    required Uri target,
  }) {
    return RedirectRequest(
      method: current.method,
      uri: target,
      headers: <String, String>{
        ...current.headers,
        'aUtHoRiZaTiOn': 'Bearer policy-secret',
        'COOKIE': 'policy=session',
      },
      body: current.body,
    );
  }
}

void main() {
  final policy = RedirectPolicy();
  final statusRequest = policy.derive(
    RedirectRequest(
      method: 'POST',
      uri: Uri.parse('https://api.example.test/uploads/17'),
      headers: const <String, String>{
        'Content-Type': 'application/json',
        'content-length': '7',
        'X-Request-Id': 'req-17',
      },
      body: const <int>[123, 34, 107, 34, 58, 49, 125],
    ),
    statusCode: 303,
    target: Uri.parse('https://api.example.test/status/17'),
  );
  check(statusRequest.method == 'GET', 'see-other changes a write into a read');
  check(statusRequest.body == null, 'see-other does not replay the entity');
  check(
    !hasHeader(statusRequest.headers, 'content-type') &&
        !hasHeader(statusRequest.headers, 'content-length'),
    'entity headers leave with the entity',
  );
  check(
    statusRequest.headers['X-Request-Id'] == 'req-17',
    'non-entity headers survive method derivation',
  );

  final storageRequest = RedirectFollower(CredentialReturningPolicy()).follow(
    RedirectRequest(
      method: 'PUT',
      uri: Uri.parse('https://api.example.test/uploads/17'),
      headers: const <String, String>{'X-Trace': 'trace-17'},
      body: const <int>[4, 5, 6],
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 307,
        location: 'https://objects.example.test/parts/17',
      ),
    ],
  );
  check(
    storageRequest.method == 'PUT',
    'temporary redirect still preserves method',
  );
  check(
    storageRequest.body?.join(',') == '4,5,6',
    'temporary redirect still preserves body',
  );
  check(
    !hasHeader(storageRequest.headers, 'authorization') &&
        !hasHeader(storageRequest.headers, 'cookie'),
    'credentials from a redirect decision stay with their origin',
  );
  check(
    storageRequest.headers['X-Trace'] == 'trace-17',
    'ordinary headers cross the redirect boundary',
  );

  print('feedback tests passed');
}
